class Solution {
    public int minStartingIndex(String s, String pattern) {
        int minIndex = -1;
        for (int i = 0; i <= s.length() - pattern.length(); i++) {
            int mismatchCount = 0;
            for (int j = 0; j < pattern.length(); j++) {
                if (s.charAt(i + j) != pattern.charAt(j)) {
                    mismatchCount++;
                    if (mismatchCount > 1) {
                        break;
                    }
                }
            }
            if (mismatchCount <= 1) {
                return i;
            }
        }
        return minIndex;
    }
}
